async (params, browser) => {
  // Open topic page
  await browser.open(`https://www.quora.com/topic/${params.topic}`)

  // Wait for topic
  await browser.waitForSelector('[class*=\'Topic\'], [class*=\'topic\'], h1', 15000)

  await browser.wait(2000)

  // Scroll for questions
  await browser.scroll({ direction: 'down', amount: 1500 })

  await browser.wait(1500)

  // Extract topic content
  const topic_data = await browser.evaluate(`const titleEl = document.querySelector('[class*="topic-name"], h1, [class*="TopicName"]'); const descEl = document.querySelector('[class*="topic-description"], [class*="description"]'); const followersEl = document.querySelector('[class*="followers"], [class*="FollowerCount"]'); const questions = []; document.querySelectorAll('[class*="question"], [class*="Question"]').forEach(function(el) { const qEl = el.querySelector('a span, [class*="text"]'); const answersEl = el.querySelector('[class*="answer-count"]'); if (qEl) { questions.push({ question: qEl.textContent.trim(), answers: answersEl ? answersEl.textContent.trim() : '', url: el.querySelector('a') ? el.querySelector('a').href : '' }); } }); return { topic: '' + params.topic + '', name: titleEl ? titleEl.textContent.trim() : '', description: descEl ? descEl.textContent.trim().substring(0, 500) : '', followers: followersEl ? followersEl.textContent.trim() : '', question_count: questions.length, questions: questions.slice(0, 20), url: window.location.href }`)

  return topic_data
}
